    30	llvm::Type*
    31	EmitIR::operator()(const Type* type)
    32	{
    33	  if (type->texp == nullptr) {
    34	    switch (type->spec) {
    35	      case Type::Spec::kInt:
    36	        return llvm::Type::getInt32Ty(mCtx);
    37	      // TODO: 在此添加对更多基础类型的处理
    38	      default:
    39	        ABORT();
    40	    }
    41	  }
    42	
    43	  Type subt;
    44	  subt.spec = type->spec;
    45	  subt.qual = type->qual;
    46	  subt.texp = type->texp->sub;
    47	
    48	  // TODO: 在此添加对指针类型、数组类型和函数类型的处理
    49	
    50	  if (auto p = type->texp->dcst<FunctionType>()) {
    51	    std::vector<llvm::Type*> pty;
    52	    // TODO: 在此添加对函数参数类型的处理
    53	    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
    54	  }
    55	
    56	  ABORT();
    57	}
