   109	EmitIR::operator()(ReturnStmt* obj)
   110	{
   111	  auto& irb = *mCurIrb;
   112	
   113	  llvm::Value* retVal;
   114	  if (!obj->expr)
   115	    retVal = nullptr;
   116	  else
   117	    retVal = self(obj->expr);
