   143	EmitIR::operator()(FunctionDecl* obj)
   144	{
   145	  // 创建函数
   146	  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));
   147	  auto func = llvm::Function::Create(
   148	    fty, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);
